import pandas as pd
import json

def validate_leads_data(file_content):
    try:
        df = pd.read_csv(file_content)
        required_columns = ['lead_id', 'name', 'company', 'budget', 'source', 'contact_time']
        missing = [col for col in required_columns if col not in df.columns]
        if missing:
            return {'valid': False, 'error': f'缺少必要列: {missing}'}
        return {'valid': True, 'row_count': len(df), 'columns': list(df.columns), 'data': df.to_dict('records')}
    except Exception as e:
        return {'valid': False, 'error': str(e)}

