def filter_by_budget(scored_leads, budget_threshold):
    high_budget = []
    low_budget = []
    for lead in scored_leads:
        if lead['score'] >= float(budget_threshold):
            high_budget.append(lead)
        else:
            low_budget.append(lead)
    return {
        'high_budget_leads': high_budget,
        'low_budget_leads': low_budget
    }

def filter_by_source(high_budget_leads, source_criteria):
    qualified_sources = [s.strip().lower() for s in source_criteria.split(',')]
    qualified = []
    unqualified = []
    for lead in high_budget_leads:
        if lead.get('source') in qualified_sources:
            qualified.append(lead)
        else:
            unqualified.append(lead)
    return {
        'qualified_leads': qualified,
        'unqualified_leads': unqualified
    }

