from datetime import datetime, timedelta

def check_leads_timeout(cleaned_data, timeout_hours=72):
    timeout_alerts = []
    for lead in cleaned_data:
        contact_time = datetime.fromisoformat(str(lead['contact_time']))
        now = datetime.now()
        hours_passed = (now - contact_time).total_seconds() / 3600
        if hours_passed > float(timeout_hours):
            timeout_alerts.append({
                'lead_id': lead['lead_id'],
                'company': lead['company'],
                'contact_time': str(lead['contact_time']),
                'hours_passed': round(hours_passed, 2)
            })
    return {'timeout_alerts': timeout_alerts}

